// // This comment suggests the counter decrements on every positive clock edge when the load signal is low, and loads the input value when the load signal is high.
module binary_counter(
	input clk,
	input reset,
	input load,
	input [7:0] load_value,
	output reg [7:0] count);always @(posedge clk) begin
		if (reset)
			count <= 8'b00000000;
		else if (load)
			count <= load_value;
		else
			count <= count + 1;
	end

endmodule
